  amount: number;
  status: string;
}

// { amount?: number | null; status?: string | null }
type OrderPatch = Patchable<Order>;
```

### 4. Conditional Types

```typescript
type ApiResponse<T> = T extends Array<infer U>
  ? { items: U[]; total: number }
  : { data: T };

// { items: string[]; total: number }
type ListResponse = ApiResponse<string[]>;

// { data: number }
type SingleResponse = ApiResponse<number>;
```

### 5. Generic Class — Type-safe Event Emitter

```typescript
class TypedEmitter<Events extends Record<string, unknown>> {
  private listeners = new Map<string, Set<Function>>();

  on<K extends keyof Events>(event: K, fn: (payload: Events[K]) => void) {
    if (!this.listeners.has(event as string)) {
      this.listeners.set(event as string, new Set());
    }
    this.listeners.get(event as string)!.add(fn);
    return () => this.listeners.get(event as string)?.delete(fn);
  }

  emit<K extends keyof Events>(event: K, payload: Events[K]) {
    this.listeners.get(event as string)?.forEach(fn => fn(payload));
  }
}

// Usage
const bus = new TypedEmitter<{
  "user:login": { userId: string };
  "cart:update": { itemCount: number };
}>();

bus.on("user:login", (e) => console.log(e.userId)); // fully typed
bus.on("cart:update", (e) => console.log(e.itemCount));
// bus.emit("user:login", { itemCount: 5 }); // compile error — wrong payload
```

### 6. Builder Pattern with Chained Generics

```typescript
class QueryBuilder<T extends Record<string, unknown>> {
  private filters: Partial<T> = {};
  private sortKey?: keyof T;

  where<K extends keyof T>(key: K, value: T[K]): this {
    this.filters[key] = value;
    return this;
  }

  orderBy(key: keyof T): this {
    this.sortKey = key;
    return this;
  }

  build() {
    return { filters: this.filters, sort: this.sortKey };
  }
}

const query = new QueryBuilder<{ name: string; age: number; active: boolean }>()
  .where("age", 25)        // OK
  .where("active", true)   // OK
  // .where("age", "old")  // compile error — expected number
  .orderBy("name")
  .build();
```

### 7. infer — Extract Return Types from Route Handlers

```typescript
type RouteMap = {
  "/users": () => Promise<{ id: string; name: string }[]>;
  "/health": () => Promise<{ status: "ok" }>;
};

type ResponseOf<R extends keyof RouteMap> =
  RouteMap[R] extends () => Promise<infer T> ? T : never;

// { id: string; name: string }[]
type UsersResponse = ResponseOf<"/users">;
```

### Mental Model

| Concept | Think of it as... |
|---------|-------------------|
| `<T>` | "caller decides type" |
| `extends` | "must be at least this shape" |
| `keyof T` | "only valid property names" |
| `T[K]` | "type of that property" |
| `infer` | "pattern-match and extract" |
| Mapped types | "transform every property" |

Key insight: generics aren't about making things "generic" — they're about **preserving relationships** between inputs and outputs so type info flows through instead of getting lost.

